const mapLineItem = (gdData) => {
  let tablePickingItems = [];
  const pickingItemGroups = new Map();

  for (const item of gdData.table_gd) {
    if (item.temp_qty_data && item.material_id) {
      const tempData = JSON.parse(item.temp_qty_data);
      for (const tempItem of tempData) {
        const materialId = String(tempItem.material_id) || String(item.material_id);
        const groupKey = `${item.id}_${materialId}_${
          tempItem.batch_id || "no-batch"
        }_${tempItem.location_id}_${tempItem.handling_unit_id || "no-hu"}`;

        if (!pickingItemGroups.has(groupKey)) {
          pickingItemGroups.set(groupKey, {
            item_code: String(materialId),
            item_name: item.material_name,
            item_desc: item.gd_material_desc || "",
            batch_no: tempItem.batch_id ? String(tempItem.batch_id) : null,
            qty_to_pick: 0,
            item_uom: String(item.good_delivery_uom_id),
            source_bin: String(tempItem.location_id),
            pending_process_qty: 0,
            line_status: "Open",
            so_no: item.line_so_no,
            gd_no: gdData.delivery_no,
            so_id: String(item.line_so_id),
            so_line_id: String(item.so_line_item_id),
            gd_id: String(gdData.id),
            gd_line_id: String(item.id),
            serial_numbers: [],
            is_serialized_item: 0,
            handling_unit_id: tempItem.handling_unit_id ? String(tempItem.handling_unit_id) : null,
          });

        }

        const group = pickingItemGroups.get(groupKey);
        group.qty_to_pick += parseFloat(tempItem.gd_quantity);
        group.pending_process_qty += parseFloat(tempItem.gd_quantity);

        if (tempItem.serial_number) {
          group.serial_numbers.push(String(tempItem.serial_number));
          group.is_serialized_item = 1;
        }
      }
    }
  }

  for (const group of pickingItemGroups.values()) {
    if (group.serial_numbers.length > 0) {
      group.serial_numbers = group.serial_numbers.join(", ");
    } else {
      delete group.serial_numbers;
    }

    tablePickingItems.push({ ...group });
  }

  tablePickingItems.sort((a, b) => {
    if (a.gd_line_id !== b.gd_line_id) return 0;
    const aHU = a.handling_unit_id || "";
    const bHU = b.handling_unit_id || "";
    if (aHU === bHU) return 0;
    return aHU < bHU ? -1 : 1;
  });

  const withHeaders = [];
  let lastHuId = null;
  for (const row of tablePickingItems) {
    const huId = row.handling_unit_id;
    if (huId && huId !== lastHuId) {
      withHeaders.push({
        row_type: "header",
        handling_unit_id: huId,
        hu_select: 0,
      });
      lastHuId = huId;
    } else if (!huId) {
      lastHuId = null;
    }
    withHeaders.push({ ...row, row_type: "item" });
  }
  tablePickingItems = withHeaders;

  return tablePickingItems;
};

const mapToPickingData = (
  pickingLineItemPromises,
  gdIDs,
  gdNos,
  soNos,
  gdCustomers,
  plantID
) => {
  return {
    so_no: soNos,
    delivery_no: gdNos,
    gd_no: gdIDs,
    ref_doc_type: "Goods Delivery",
    table_picking_items: pickingLineItemPromises,
    customer_id: gdCustomers,
    plant_id: plantID,
  };
};

const pickingSetup = {{node:get_node_XlbxIscw.data.data}} || {};
const allowFullPicking = pickingSetup.allow_full_picking === 1;

// When allow_full_picking is ON, rewrite each line's temp_qty_data to the
// actually-remaining allocation by subtracting picked_temp_qty_data per
// (location, batch, HU). This way the next Picking only pulls from bins/batches
// that still have qty left, instead of re-allocating already-picked stock.
const subtractPickedFromTemp = (gdItem) => {
  let tempArr = [];
  try {
    tempArr = gdItem.temp_qty_data ? JSON.parse(gdItem.temp_qty_data) : [];
  } catch (e) { tempArr = []; }

  let pickedArr = [];
  try {
    pickedArr = gdItem.picked_temp_qty_data
      ? JSON.parse(gdItem.picked_temp_qty_data)
      : [];
  } catch (e) { pickedArr = []; }

  if (!Array.isArray(tempArr) || tempArr.length === 0) return gdItem;
  if (!Array.isArray(pickedArr) || pickedArr.length === 0) return gdItem;

  const keyOf = (e) =>
    (e.location_id || 'no-loc') + '_' +
    (e.batch_id || 'no-batch') + '_' +
    (e.handling_unit_id || 'no-hu');

  const pickedByKey = new Map();
  for (const p of pickedArr) {
    const k = keyOf(p);
    pickedByKey.set(k, (pickedByKey.get(k) || 0) + parseFloat(p.gd_quantity || 0));
  }

  const remaining = [];
  for (const t of tempArr) {
    const used = pickedByKey.get(keyOf(t)) || 0;
    const rem = parseFloat(t.gd_quantity || 0) - used;
    if (rem > 0) {
      remaining.push({ ...t, gd_quantity: rem });
    }
  }

  return { ...gdItem, temp_qty_data: JSON.stringify(remaining) };
};

let gdData = {{node:search_node_IUyBiDce.data.data}};
gdData = gdData.map((item) => ({
  ...item,
  table_gd: item.table_gd
    .filter((gdItem) => {
      if (allowFullPicking) {
        const remaining = (gdItem.gd_qty || 0) - (gdItem.picked_qty || 0);
        return (
          remaining > 0 &&
          gdItem.picking_status !== 'Completed' &&
          gdItem.picking_status !== 'Cancelled'
        );
      }
      return gdItem.picking_status === 'Not Created';
    })
    .map((gdItem) => (allowFullPicking ? subtractPickedFromTemp(gdItem) : gdItem))
}));

const gdIDs = gdData.map((gd) => String(gd.id));
const gdNos = gdData.map((gd) => gd.delivery_no).join(', ');
const soNos = [
  ...new Set(gdData.flatMap((gd) => gd.so_no.split(', ')))
].join(', ');
const gdCustomers = [ ...new Set(gdData.map((gd) => String(gd.customer_name)))];
const plantID = {{workflowparams:plant_id}};
let pickingLineItemPromises = [];

for(const gd of gdData) {
  const lineItemPromise = mapLineItem(gd);
  pickingLineItemPromises.push(...lineItemPromise);
}

const pickingData = mapToPickingData(pickingLineItemPromises, gdIDs, gdNos, soNos, gdCustomers, plantID);

return pickingData;
